    uint256 challengeId;
    address subject;
    uint64  periodStart;
    uint64  periodEnd;
    uint8   ruleKind;
    uint32  minDaily;
    bytes32 datasetHash;
    bool    pass;
    uint256 chainId;
    address verifier;
  }

