      abi.encode(
        ATTESTATION_TYPEHASH,
        a.challengeId,
        a.subject,
        a.periodStart,
        a.periodEnd,
        a.ruleKind,
        a.minDaily,
        a.datasetHash,
        a.pass,
        a.chainId,
        a.verifier
